import { type FillOptions, type Variants } from "./types";

type ButtonProps = React.ButtonHTMLAttributes<HTMLButtonElement> & {
    variant?: Variants;
    fill?: FillOptions;
    disabled?: boolean;
};

export function Button({variant='primary', fill='solid', disabled, ...htmlButtonProps}: ButtonProps) {
  return <button {...htmlButtonProps} />;
}
